 1	import { type FC, type Ref, useState } from 'react';
 2	
 3	import type { ProviderType, V1beta1Plan } from '@kubev2v/types';
 4	import { Dropdown, MenuToggle, type MenuToggleElement } from '@patternfly/react-core';
 5	import { EllipsisVIcon } from '@patternfly/react-icons';
 6	
 7	import SpecVirtualMachinesActionsDropdownItems from './SpecVirtualMachinesActionsDropdownItems';
 8	
 9	type SpecVirtualMachinesActionsDropdownProps = {
10	  plan: V1beta1Plan;
11	  vmIndex: number;
12	  providerType: ProviderType;
13	};
14	
15	const SpecVirtualMachinesActionsDropdown: FC<SpecVirtualMachinesActionsDropdownProps> = ({
16	  plan,
17	  providerType,
18	  vmIndex,
19	}) => {
20	  const [isOpen, setIsOpen] = useState(false);
21	
22	  const onToggleClick = () => {
23	    setIsOpen((open) => !open);
24	  };
25	
26	  const onSelect = () => {
27	    setIsOpen(false);
28	  };
29	
30	  return (
31	    <Dropdown
32	      className="forklift-dropdown"
33	      isOpen={isOpen}
34	      onOpenChange={setIsOpen}
35	      onSelect={onSelect}
36	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
37	        <MenuToggle
38	          ref={toggleRef}
39	          onClick={onToggleClick}
40	          isExpanded={isOpen}
41	          variant="plain"
42	          data-testid="vm-actions-menu-toggle"
43	        >
44	          <EllipsisVIcon />
45	        </MenuToggle>
46	      )}
47	      shouldFocusToggleOnSelect
48	      popperProps={{
49	        position: 'right',
50	      }}
51	    >
52	      <SpecVirtualMachinesActionsDropdownItems
53	        plan={plan}
54	        vmIndex={vmIndex}
55	        providerType={providerType}
56	      />
57	    </Dropdown>
58	  );
59	};
60	
61	export default SpecVirtualMachinesActionsDropdown;

